/* ===== MODAL ===== */
.modal-overlay {
  position: fixed;     /* Menutupi seluruh layar */
  inset: 0;            /* top:0, right:0, bottom:0, left:0 */
  background: rgba(0, 0, 0, 0.5);
  display: flex;
  align-items: center;
  justify-content: center;
  z-index: 100;
  opacity: 0;           /* Default: transparan */
  pointer-events: none; /* Default: tidak bisa di-klik */
  transition: opacity 0.25s ease;
}

.modal-overlay.active {
  opacity: 1;
  pointer-events: all; /* JS tambahkan class 'active' untuk tampilkan */
}

.modal-box {
  background: #fff;
  border-radius: var(--radius);
  padding: 1.5rem;
  width: min(480px, 90vw); /* Responsif: maks 480px atau 90% lebar layar */
  transform: translateY(-20px);
  transition: transform 0.25s ease;
}

.modal-overlay.active .modal-box {
  transform: translateY(0); /* Animasi slide-down saat aktif */
}

/* ===== TOAST NOTIFICATION ===== */
.toast {
  position: fixed;
  bottom: 1.5rem;
  right: 1.5rem;
  padding: 0.75rem 1.25rem;
  border-radius: var(--radius);
  color: #fff;
  font-weight: 600;
  font-size: 0.875rem;
  opacity: 0;
  transform: translateY(20px);
  transition: opacity 0.3s, transform 0.3s;
  z-index: 200;
}

.toast.show {
  opacity: 1;
  transform: translateY(0);
}

.toast.success { background: var(--success); }
.toast.error   { background: var(--danger);  }

// Ini preview — akan dikerjakan penuh di Pertemuan 5
// Tujuan: pahami MENGAPA kita butuh struktur HTML & CSS yang sudah dibuat

const modalOverlay = document.getElementById('modalOverlay');
const toastNotif   = document.getElementById('toastNotif');

// Tampilkan modal
function openModal() {
  modalOverlay.classList.add('active'); // CSS yang mengurus animasinya
}

// Tutup modal
function closeModal() {
  modalOverlay.classList.remove('active');
}

// Tampilkan toast notification
function showToast(message, type = 'success') {
  toastNotif.textContent = message;
  toastNotif.className   = `toast ${type} show`;
  setTimeout(() => {
    toastNotif.classList.remove('show'); // Auto-hilang setelah 2.5 detik
  }, 2500);
}

